<script setup lang="ts">import { computed } from 'vue';import type { Agent,Room,RunSnapshot } from '../domain/types';import ProgressScroll from './ProgressScroll.vue';import MarkdownContent from './MarkdownContent.vue';import { fileDownloadUrl } from '../api/client';const p=defineProps<{run:RunSnapshot;rooms:readonly Room[];agents:readonly Agent[]}>();const phase=computed(()=>({queued:'等待受理',planning:'谋划任务',dispatching:'分派各院',discussing:'诸室会商',synthesizing:'首席汇总',publishing:'刊行卷宗',completed:'圆满完成',partial_failed:'部分完成',failed:'任务失败',cancelled:'任务取消'}[p.run.phase]));const activeNames=computed(()=>p.run.activeAgentIds.map(id=>p.agents.find(a=>a.id===id)?.name).filter(Boolean).join('、'));</script>
<template><section class="central-hall panel" aria-labelledby="hall-title"><div class="hall-plaque"><small>问道主殿</small><h1 id="hall-title">{{phase}}</h1></div><ProgressScroll :value="run.progress"/><div class="hall-stats"><span><b>{{run.completedRoomIds.length}}</b>/{{rooms.length}} 研究室完成</span><span><b>{{Object.values(run.roomRuns).filter(r=>['discussing','synthesizing'].includes(r.status)).length}}</b> 室会商中</span><span><b>{{run.activeAgentIds.length}}</b> 位大师活跃</span></div><blockquote v-if="run.question"><small>本次问卷</small>{{run.question}}</blockquote><div v-else class="empty-state">尚无问卷。进入中央房间向诸位大师提问。</div><p v-if="activeNames" class="active-line"><span class="pulse-dot"></span>{{activeNames}} 正在推演</p><article v-if="run.finalAnswer" class="final-answer"><header><span>钤印定稿</span><h2>最终完整结论</h2></header><MarkdownContent :content="run.finalAnswer" :team-id="run.teamId"/><a v-if="run.reportPath" class="report-download" :href="fileDownloadUrl(run.reportPath,run.teamId)" target="_blank" rel="noopener">下载完整 Markdown 报告</a></article><div class="publish-state" :class="run.publication.status"><b>博客卷宗</b><span>{{({idle:'等待最终结论',pending:'等待发布',publishing:'正在刊行',published:'已发布',failed:'发布遇阻'} as const)[run.publication.status]}}</span><a v-if="run.publication.url" :href="run.publication.url" target="_blank" rel="noopener noreferrer">查看博客文章</a></div></section></template>
